WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/50.0/connection.js")}
        {!REQUIRESCRIPT("/soap/ajax/50.0/apex.js")}

        var idList = '{!Contact.Id}';
        var resultItem = new sforce.SObject("ts2__s_ResultItem__c");
        if (resultItem) {
            resultItem.ts2__sel_contact_id_list__c = idList;
            var createRiResult = sforce.connection.create([resultItem]);
            if (createRiResult && createRiResult[0].getBoolean("success")) {
                var resultId = createRiResult[0].id;
                var url = "/apex/ts2__add_skills_temp?cId=" + resultId + '&src=resultitem';
                var features = 'directories=no,menubar=no,titlebar=no,toolbar=no,width=900,height=590';
                var win = window.open(url,'', features);
                win.focus();
                var closeWindow = setInterval(() => {
                    if (win.closed) {
                        window.location.reload();
                        clearTimeout(closeWindow);
                    }
                }, 200);
            }
        }
